// BOOKING SYSTEM v2 пњљ State Machine + Autofill + Confirmation
// вХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХРвХР
const ADMIN_EMAIL = 'moralesplumbing026@gmail.com';

let bookingData = { name: '', phone: '', address: '', service: '', date: '', time: '', notes: '' };
const BOOKING_FIELDS = ['name', 'phone', 'address', 'service', 'date', 'time'];

// Booking conversation state machine
let bookingState = {
    active: false,
    step: 0,  // 0=idle, 1=name, 2=phone, 3=address, 4=service, 5=date, 6=time, 7=notes, 8=confirm
    lang: 'es'
};

